// Build the evening check-in message
const meals = $input.all().map(i => i.json);

let totalCal = 0, totalProtein = 0, totalCarbs = 0, totalFat = 0;
for (const m of meals) {
  totalCal += m.calories || 0;
  totalProtein += parseFloat(m.protein_g) || 0;
  totalCarbs += parseFloat(m.carbs_g) || 0;
  totalFat += parseFloat(m.fat_g) || 0;
}

const today = new Date();
const dayOfWeek = today.getDay();
const isTrainingDay = [1, 3, 5].includes(dayOfWeek);
const goal = isTrainingDay ? 2100 : 1900;

const foodSummary = meals.length > 0 
  ? `You logged ${meals.length} meals today: ${totalCal} kcal, ${totalProtein.toFixed(0)}g protein (goal: ${goal} kcal, 170g protein)`
  : 'No food logged today!';

const onTrack = totalCal > 0 && totalCal <= goal + 100 && totalProtein >= 140;

const message = `Hey! Time for your evening check-in.

Food: ${foodSummary}
${onTrack ? 'Looking good on nutrition today.' : 'Nutrition could use some work.'}

Now tell me about the rest of your day. Which of these did you do?

- Sleep (8 hours last night?)
- Workout
- 10,000 steps
- Read/Learn 30 min
- Supplements
- Calendar & Reflection
- Positivity/Gratefulness

Just reply with what you did (text or voice note). I\'ll log everything for you.`;

return [{ json: { message, totalCal, totalProtein, totalCarbs, totalFat, isTrainingDay, goal, mealCount: meals.length } }];

// Parse the user's reply to determine which habits were completed
const reply = ($json.message?.text || '').toLowerCase();

// Smart matching for each habit
const habits = {
  sleep_8h: /sleep|slept|8\s*h|well.rested|good\s*night/i.test(reply),
  eat_healthy: /eat|ate|healthy|clean|on\s*plan|nutrition/i.test(reply) || $node['Build Check-in Message'].json.totalCal > 0,
  workout_done: /workout|gym|train|weights|cardio|exercise|lift/i.test(reply),
  steps_10k: /step|walk|10k|10,?000/i.test(reply),
  read_30min: /read|book|learn|study|article|podcast/i.test(reply),
  supplements: /supplement|pill|vitamin|magnesium|omega|creatine/i.test(reply),
  positivity: /positiv|grateful|thankful|gratefulness|mindful|meditat/i.test(reply),
  calendar_reflection: /calendar|reflect|plan|journal|review/i.test(reply)
};

// Count completed habits
const completed = Object.values(habits).filter(Boolean).length;
const total = Object.keys(habits).length;
const percentage = Math.round((completed / total) * 100);

return [{ json: { habits, completed, total, percentage, rawReply: reply } }];

